import{_ as l,C as s,o as i,c as r,j as t,E as n,a,a3 as g}from"./chunks/framework.DACwFHq9.js";const k=JSON.parse('{"title":"文本处理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/text-processing.md","filePath":"user-guide/tools/llm-chat/settings/text-processing.md","lastUpdated":1778244893000}'),d={name:"user-guide/tools/llm-chat/settings/text-processing.md"},c={id:"文本处理",tabindex:"-1"};function u(h,o,p,m,x,b){const e=s("LIcon");return i(),r("div",null,[t("h1",c,[n(e,{name:"Regex",size:"28"}),o[0]||(o[0]=a(" 文本处理 ",-1)),o[1]||(o[1]=t("a",{class:"header-anchor",href:"#文本处理","aria-label":'Permalink to "<LIcon name="Regex" size="28" /> 文本处理"'},"​",-1))]),o[2]||(o[2]=g('<p>文本处理模块负责对聊天上下文进行自动化的格式转换与内容清洗，是保持上下文整洁、节约 Token 的关键。</p><h2 id="上下文优化-context-optimization" tabindex="-1">上下文优化 (Context Optimization) <a class="header-anchor" href="#上下文优化-context-optimization" aria-label="Permalink to &quot;上下文优化 (Context Optimization)&quot;">​</a></h2><ul><li><strong>HTML 转 MD</strong>: <ul><li><strong>功能</strong>: 自动将历史消息中的 HTML 标签（如 Web 搜索返回的结果）转换为 Markdown。</li><li><strong>优势</strong>: 显著降低 Token 消耗（HTML 标签通常非常冗长），并提高模型对内容的理解准确度。</li></ul></li><li><strong>转换阈值</strong>: <ul><li>控制“保鲜期”。例如设为 5，则最近 5 条消息保留原始 HTML 以保证 UI 渲染（如预览模式）不受影响，更早的消息则被转换为 Markdown。</li></ul></li></ul><h2 id="正则替换规则-regex-rules" tabindex="-1">正则替换规则 (Regex Rules) <a class="header-anchor" href="#正则替换规则-regex-rules" aria-label="Permalink to &quot;正则替换规则 (Regex Rules)&quot;">​</a></h2><p>正则替换是 LLM Chat 中最强大的文本处理工具。它允许你通过正则表达式，在消息**发送给 AI 之前（请求层）<strong>或</strong>显示在屏幕上时（渲染层）**对文本进行自动修改。</p><h3 id="核心概念-两个关键阶段" tabindex="-1">核心概念：两个关键阶段 <a class="header-anchor" href="#核心概念-两个关键阶段" aria-label="Permalink to &quot;核心概念：两个关键阶段&quot;">​</a></h3><p>理解规则生效的“位置”至关重要：</p><ol><li><strong>🎨 渲染层 (Render)</strong>: <ul><li><strong>只改显示，不改记忆</strong>。就像给照片加滤镜。</li><li><strong>作用</strong>: 修改消息在 UI 界面上的呈现方式。</li><li><strong>场景</strong>: 隐藏思考过程、美化特定输出格式、遮蔽敏感词。</li></ul></li><li><strong>🚀 请求层 (Request)</strong>: <ul><li><strong>修改记忆，永久生效</strong>。就像在 PS 里修图。</li><li><strong>作用</strong>: 修改实际发送给 AI 的 Prompt（提示词）。</li><li><strong>场景</strong>: 删除冗长的 HTML 标签以节省 Token、修正模型总是写错的专有名词、清洗上下文。</li></ul></li></ol><h3 id="绑定模式-binding-mode" tabindex="-1">绑定模式 (Binding Mode) <a class="header-anchor" href="#绑定模式-binding-mode" aria-label="Permalink to &quot;绑定模式 (Binding Mode)&quot;">​</a></h3><p>决定了历史消息如何应用正则配置：</p><ul><li><strong>跟随消息配置 (Message)</strong>: 采用“配置快照”原则。每条历史消息都使用它产生时所关联的正则规则。这能保证历史数据的表现一致性，不会因为你今天改了规则就导致昨天的消息显示异常。</li><li><strong>使用当前会话配置 (Session)</strong>: 所有历史消息都动态应用当前会话正在使用的规则。适合需要快速全局调整表现的场景。</li></ul><h3 id="规则详解与高级功能" tabindex="-1">规则详解与高级功能 <a class="header-anchor" href="#规则详解与高级功能" aria-label="Permalink to &quot;规则详解与高级功能&quot;">​</a></h3><p>每条规则都包含以下精细控制项：</p><div><ul><li><strong>目标角色</strong>: 指定规则仅对 <code>System</code>、<code>User</code> 或 <code>Assistant</code> 的消息生效。</li><li><strong>深度范围</strong>: 限制规则仅在对话的特定深度（如最近 5 轮）生效。</li><li><strong>宏替换 (Macros)</strong>: <ul><li>支持在正则或替换内容中使用 <code>{{user}}</code> (用户名) 或 <code>{{char}}</code> (角色名) 等动态变量。</li><li><strong>转义模式</strong>: 推荐使用 <code>Escaped</code> 模式，系统会自动处理用户名中的特殊字符（如 <code>C.C.</code>），防止破坏正则语法。</li></ul></li><li><strong>后处理 (Trim Strings)</strong>: 在正则捕获后，自动移除捕获组内容中不需要的特定字符串（如多余的省略号）。</li></ul></div><h3 id="调试与效率工具" tabindex="-1">调试与效率工具 <a class="header-anchor" href="#调试与效率工具" aria-label="Permalink to &quot;调试与效率工具&quot;">​</a></h3><p>为了降低正则编写的门槛，编辑器内置了强大的辅助功能：</p><ul><li><strong>预制规则库</strong>: 提供了“折叠思考块”、“移除多余空行”、“URL 转链接”等常用模板。点击即可快速填充，无需从零开始编写。</li><li><strong>内置规则测试</strong>: <ul><li>编辑器底部包含一个<strong>测试沙箱</strong>。</li><li>你可以输入一段测试文本，系统会实时显示匹配次数。</li><li><strong>实时预览</strong>: 匹配到的内容会以黄色高亮显示；如果设置了替换内容，替换后的结果会以绿色高亮显示，让你在保存前就能确认效果。</li></ul></li><li><strong>脚本处理 (高级)</strong>: 除了简单的文本替换，你还可以切换到“脚本处理”模式。通过编写简单的 JavaScript 代码（支持 <code>match</code>, <code>groups</code> 等变量），实现如“将匹配文字转为大写”等复杂的逻辑加工。</li></ul><h3 id="预设管理与兼容性" tabindex="-1">预设管理与兼容性 <a class="header-anchor" href="#预设管理与兼容性" aria-label="Permalink to &quot;预设管理与兼容性&quot;">​</a></h3><ul><li><strong>多级预设</strong>: 规则按“预设 (Preset)”分组。你可以为不同的场景（如“通用清洗”、“赛博朋克 UI”）创建不同的预设。</li><li><strong>优先级</strong>: 数值越小越先执行（默认 100）。</li><li><strong>导入导出</strong>: <ul><li>支持 AIO 原生 JSON 格式。</li><li><strong>酒馆兼容</strong>: 完美支持导入 <strong>SillyTavern (酒馆)</strong> 的正则预设文件。</li></ul></li><li><strong>安全检查</strong>: 导入包含脚本执行能力的规则时，系统会自动进行风险扫描，防止恶意代码执行。</li></ul><hr><div class="warning custom-block"><p class="custom-block-title">警告</p><p>正则规则具有全局破坏性。错误的正则表达式可能导致消息内容被误删或显示异常。请务必利用编辑器内置的<strong>规则测试</strong>功能先行验证。</p></div>',21))])}const T=l(d,[["render",u]]);export{k as __pageData,T as default};
